{"code": "import json
import os

common_symbols_path = locals()['var_functions.execute_python:16']
with open(common_symbols_path, 'r') as f:
    common_symbols = json.load(f)

etfs_over_200 = []

print(f"Checking {len(common_symbols)} ETFs for 2015 prices over $200...")

# We'll check in batches to avoid overwhelming the system
sample_symbols = common_symbols[:50]  # Sample first 50 for testing

results = []
for symbol in sample_symbols:
    try:
        query_db_result = query_db(
            db_name="stocktrade_database",
            query=f'SELECT "Adj Close", Date FROM "{symbol}" WHERE Date BETWEEN \'2015-01-01\' AND \'2015-12-31\' AND "Adj Close" > 200.0 LIMIT 1;'
        )

        if query_db_result and len(query_db_result) > 0:
            results.append({
                'symbol': symbol,
                'has_data': True,
                'sample_price': query_db_result[0]['Adj Close']
            })
        else:
            results.append({
                'symbol': symbol,
                'has_data': False
            })
    except Exception as e:
        # Table might not exist or other error
        results.append({
            'symbol': symbol,
            'error': str(e)
        })

print(f"Checked {len(results)} ETFs")
print(f"Sample results: {results[:10]}")"}

